// containsHexLetter reports whether s contains a hex letter (a-f / A-F).
// A hex run with no letter is pure decimal and far more likely to be an
// issue number, timestamp, or version than an abbreviated git hash.
func containsHexLetter(s string) bool {
	for i := 0; i < len(s); i++ {
		c := s[i]
		if (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F') {
			return true
		}
	}
	return false
}

